// // This is a 16-bit Johnson counter with an active low synchronous reset. It outputs a 16-bit vector q, where each bit represents the state of a counter. The Johnson counter resets to all ones on reset.
module top_module(
	input clk,
	input reset,
	output reg [15:0] q);always @(posedge clk) begin
		if (reset)
			q <= 16'b0;
		else begin
			q[0] <= ~q[15];
			q[15:1] <= q[14:0];
		end
	end
endmodule
